const allowedExtensions = new Set([
  'pdf', 'png', 'jpg', 'jpeg', 'tif', 'tiff', 'gif', 'webp', 'txt',
  'doc', 'docx', 'odt', 'ppt', 'pptx', 'odp', 'xls', 'xlsx', 'ods', 'eml'
]);

const item = $input.first();
const binary = item?.binary ?? {};
const binaryKeys = Object.keys(binary);
const binaryFieldName = binary.data ? 'data' : binaryKeys[0];
const file = binaryFieldName ? binary[binaryFieldName] : null;
const fallbackName = binaryFieldName ? `datei-aus-${binaryFieldName}` : 'unbekannt';
const filename = file?.fileName || fallbackName;
const extension = filename.includes('.') ? filename.split('.').pop().toLowerCase() : '';

if (!file) {
  return [{
    json: {
      isValid: false,
      done: true,
      isSuccess: false,
      status: 'failure',
      filename: 'unbekannt',
      errorReason: 'Keine Binary-Datei im Input gefunden.',
      signalMessage: 'Paperless: unbekannt konnte nicht hochgeladen werden'
    }
  }];
}

if (!extension || !allowedExtensions.has(extension)) {
  return [{
    json: {
      isValid: false,
      done: true,
      isSuccess: false,
      status: 'failure',
      filename,
      errorReason: `Dateityp .${extension || 'unbekannt'} wird von diesem Workflow nicht unterstuetzt.`,
      signalMessage: `Paperless: ${filename} konnte nicht hochgeladen werden`
    },
    binary,
  }];
}

return [{
  json: {
    isValid: true,
    done: false,
    isSuccess: false,
    status: 'ready',
    filename,
    extension,
    binaryFieldName
  },
  binary,
}];

const filename = $('Prepare input').item.json.filename || 'unbekannt';
const reason = $json.message || $json.error?.message || 'HTTP-Fehler beim Upload zu Paperless.';

return [{
  json: {
    done: true,
    isSuccess: false,
    status: 'failure',
    filename,
    errorReason: reason,
    signalMessage: `Paperless: ${filename} konnte nicht hochgeladen werden`
  }
}];

const source = $('Prepare input').item.json;
const filename = source.filename || 'unbekannt';
const payload = $json;

let taskId = payload?.task_id ?? payload?.taskId ?? payload?.id ?? payload?.uuid ?? null;
if (!taskId && typeof payload === 'string') taskId = payload;
if (!taskId && typeof payload?.data === 'string') taskId = payload.data;
if (!taskId && payload?.data?.task_id) taskId = payload.data.task_id;

if (!taskId) {
  return [{
    json: {
      done: true,
      isSuccess: false,
      status: 'failure',
      filename,
      errorReason: 'Paperless hat keine task_id fuer den Upload geliefert.',
      signalMessage: `Paperless: ${filename} konnte nicht hochgeladen werden`
    }
  }];
}

return [{
  json: {
    done: true,
    isSuccess: true,
    status: 'success',
    filename,
    taskId,
    taskStatus: 'ACCEPTED',
    attempts: 0,
    maxAttempts: 36,
    pollDelaySeconds: 5,
    signalMessage: `Paperless: ${filename} wurde erfolgreich hochgeladen`
  }
}];

const ctx = $('Wait before polling').item.json;
const filename = ctx.filename || 'unbekannt';
const response = $json;
const results = Array.isArray(response.results) ? response.results : [];
const task = results[0] || response.task || null;
const statusRaw = (task?.status || task?.state || response.status || '').toString().toUpperCase();

const attempts = Number(ctx.attempts || 0) + 1;
const maxAttempts = Number(ctx.maxAttempts || 36);

const doneByStatus = statusRaw === 'SUCCESS' || statusRaw === 'FAILURE';
const timedOut = attempts >= maxAttempts && !doneByStatus;
const done = doneByStatus || timedOut;
const isSuccess = statusRaw === 'SUCCESS';

let errorReason = '';
if (statusRaw === 'FAILURE') {
  errorReason = task?.result || task?.error || 'Paperless meldet FAILURE.';
}
if (timedOut) {
  errorReason = `Timeout nach ${attempts} Polling-Versuchen.`;
}

let signalMessage = '';
if (done) {
  signalMessage = isSuccess
    ? `Paperless: Dokument ${filename} wurde hinzugefuegt`
    : `Paperless: ${filename} konnte nicht hochgeladen werden`;
}

return [{
  json: {
    ...ctx,
    attempts,
    done,
    isSuccess,
    status: done ? (isSuccess ? 'success' : 'failure') : 'running',
    taskStatus: statusRaw || 'UNKNOWN',
    documentId: task?.related_document || task?.document_id || task?.documentId || null,
    errorReason,
    signalMessage
  }
}];

return items.map((item) => ({
  json: {
    ...item.json,
    message: item.json.signalMessage || '',
    recipient: ''
  }
}));

const inputItems = $input.all();
const prepared = $('Prepare Signal payload').all();

return inputItems.map((item, index) => {
  const source = prepared[index]?.json || prepared[0]?.json || {};
  const signal = item.json || {};

  return {
    json: {
      status: source.status || (source.isSuccess ? 'success' : 'failure'),
      filename: source.filename || null,
      taskId: source.taskId || null,
      taskStatus: source.taskStatus || null,
      documentId: source.documentId || null,
      errorReason: source.errorReason || null,
      signal
    }
  };
});
